class TrieNode {
public:
    char char;
    unordered_map<char, TrieNode*> children;

    TrieNode(char c) : char(c) {}

    void add_child(char c) {
        children[c] = new TrieNode(c);
    }

    void remove_child(char c) {
        if (children.find(c) != children.end()) {
            delete children[c];
            children.erase(c);
        }
    }

    bool has_child(char c) {
        return children.find(c) != children.end();
    }
};

class Trie {
public:
    TrieNode* root;

    Trie() : root(new TrieNode('')) {}

    void insert(string word) {
        TrieNode* node = root;
        for (char c : word) {
            if (node->children.find(c) == node->children.end()) {
                node->add_child(c);
            }
            node = node->children[c];
        }
    }

    ~Trie() {
        delete root;
    }
};

int main() {
    Trie trie;
    trie.insert('apple');
    trie.insert('banana');
    // Test the Trie
    std::cout << trie.root->char << std::endl; // Should print ''
    for (char c : 'apple') {
        std::cout << trie.root->children[c]->char << std::endl; // Should print 'a', 'p', 'p', 'l', 'e'
    }
    std::cout << trie.root->children['a']->has_child('a') << std::endl; // Should print 1
    return 0;
}
